import pandas as pd
import os

# Paths to the CSV that stores the results of the 9 sensitivity‑analysis runs
csv_path = os.path.join(os.path.dirname(__file__), 'sensitivity_results.csv')
excel_path = os.path.join(os.path.dirname(__file__), 'hyperparameter_comparison.xlsx')

# ---------------------------------------------------------------------------
# Load the CSV produced by `sensitivity_analysis.py`
# Expected columns in the CSV (as generated by the original script):
#   Case, Batch size, Learning rate, Epoch, dropout, R2, RMSE, MAE
# ---------------------------------------------------------------------------

df = pd.read_csv(csv_path)

# ---------------------------------------------------------------------------
# Baseline values from the reference Auto‑ML paper (Shivendu Mishra et al.)
#   * MAE  = 0.0097
#   * RMSE = 0.0127
# These are used to compute Δ values and percent improvements.
# ---------------------------------------------------------------------------
BASE_MAE = 0.0097
BASE_RMSE = 0.0127

# Compute delta columns (our metric – baseline). Negative values mean an improvement.
df['Δ_RMSE'] = df['RMSE'] - BASE_RMSE
df['Δ_MAE'] = df['MAE'] - BASE_MAE

# Compute percent improvement (how much of the baseline error we eliminated).
# Positive percentages indicate a reduction in error.
df['%_RMSE_Improvement'] = ((BASE_RMSE - df['RMSE']) / BASE_RMSE) * 100
df['%_MAE_Improvement'] = ((BASE_MAE - df['MAE']) / BASE_MAE) * 100

# Add a human‑readable comment based on the R^2 score. Threshold 0.88 marks a "good" model.
R2_THRESHOLD = 0.88

def r2_comment(val):
    if val >= 0.88:
        return 'Accurate'
    else:
        return 'Inaccurate'

df['Comment'] = df['R2'].apply(r2_comment)

# ---------------------------------------------------------------------------
# Write the enriched DataFrame to an Excel workbook. Basic styling is applied so the
# sheet is ready for inclusion in a manuscript.
# ---------------------------------------------------------------------------
with pd.ExcelWriter(excel_path, engine='openpyxl') as writer:
    df.to_excel(writer, index=False, sheet_name='Comparison')
    # Optional styling – highlight the best row (lowest MAE) in green.
    try:
        import openpyxl
        ws = writer.sheets['Comparison']
        # Find the row with minimum MAE (skip header row which is row 1).
        mae_col_idx = list(df.columns).index('MAE') + 1  # 1‑based Excel index
        min_mae = df['MAE'].min()
        for row in range(2, ws.max_row + 1):
            if ws.cell(row=row, column=mae_col_idx).value == min_mae:
                for col in range(1, ws.max_column + 1):
                    ws.cell(row=row, column=col).fill = openpyxl.styles.PatternFill(start_color='C6EFCE', fill_type='solid')
                break
    except Exception:
        # Styling is optional; failure should not stop script execution.
        pass

print(f'Generated {excel_path}')
